query:
-- 步驟 1：刪除測試客戶相關的 assignments
DELETE assignments FROM assignments
INNER JOIN demands ON assignments.demandId = demands.id
WHERE demands.clientId != 630001;

-- 步驟 2：刪除測試客戶相關的 demands
DELETE FROM demands WHERE clientId != 630001;

-- 步驟 3：刪除所有測試客戶（保留 id=630001 的米窩）
DELETE FROM clients WHERE id != 630001;

-- 步驟 4：確認結果
SELECT COUNT(*) AS remaining_clients FROM clients;
SELECT COUNT(*) AS remaining_demands FROM demands;
SELECT COUNT(*) AS remaining_assignments FROM assignments;

